import React, { useEffect, useState } from 'react';
import axios from 'axios';

function decodeUnicode(str) {
  return str.replace(/\\u([\dA-F]{4})/gi, (match, grp) => {
    return String.fromCharCode(parseInt(grp, 16));
  });
}
function Countries({ setToken }) {
    const [countries, setCountries] = useState([]);
    const [loading, setLoading] = useState(true);
    const [error, setError] = useState(null);

    useEffect(() => {
      axios.get('http://192.168.66.59:5000/api/countries')
        .then(response => {
          const decodedCountries = response.data.map(country => ({...country, name: decodeUnicode(country.name),
          }));
          setCountries(decodedCountries);
          setLoading(false);
          })
          .catch(err => { setError('Failed to populate country list'); setLoading(false); console.error('error', err);
          });
    }, []);
    return (
    <div className="App">
      <h1>Страны</h1>
      {error && <p className="error-message">{error}</p>}
      {loading ? <p>Loading countries...</p> : (
        <ul>
          {countries.map(country => (
            <li key={country.id}>{country.name}</li>
          ))}
        </ul>
      )}
    </div>
  );
}

export default Countries;
